import 'bootstrap';
import { FaCloudDownloadAlt } from 'react-icons/fa';
import resume from './files/RobertJollyResume.pdf';


const Navbar = ({handleScroll}) => {
	return (
		<div className="containerNavbar" >
			<nav className="navbar navbar-expand-md bg-dark navbar-dark justify-content-center" style={{padding:'10px'}} >
				<span style={{color:'white', paddingRight:'5px'}}> <span style={{fontWeight:'bold'}}>Robert</span>Jolly</span>
			  <button className="navbar-toggler" type="button" data-toggle="collapse" data-target="#collapsibleNavbar">
			    <span className="navbar-toggler-icon"></span>
			  </button>
			  <div className="collapse navbar-collapse justify-content-center" id="collapsibleNavbar">
			    <ul className="navbar-nav">
			      <li className="nav-item">
			        <a className="nav-link" href="/portfolio">Home</a>
			      </li>
				    <li className="nav-item">
			        <a className="nav-link" href="/portfolio/contact">Contact</a>
			      </li>
				    <li className="nav-item dropdown">
				      <a 
				      	className="nav-link dropdown-toggle" 
				      	id="navbardrop" 
				      	href="!#" 
				      	data-toggle="dropdown"
				      	style={{cursor:'default'}}
				      >
				        Projects
				      </a>
				      <div className="dropdown-menu">
				        <a className="dropdown-item" href="/portfolio" onClick={(e) => handleScroll(e, 'survive')}>Survive</a>
				        <a className="dropdown-item" href="/portfolio" onClick={(e) => handleScroll(e, 'fantasy')}>Fantasy Football</a>
				        <a className="dropdown-item" href="/portfolio" onClick={(e) => handleScroll(e, 'yahtzee')}>JollyYahtzee</a>
				        <a className="dropdown-item" href="/portfolio" onClick={(e) => handleScroll(e, 'portfolio')}>My Portfolio</a>
				      </div>
				    </li>
				    <a href={resume} download>
				    	<span className="navbar-text" style={{position:'absolute', right:'0'}} >
				      	Resume
				      	<FaCloudDownloadAlt style={{margin:'0px 10px 5px 5px'}} size='25'/>
				    	</span>
				    </a>

			    </ul>
			  </div>
			</nav>		
		</div>
	)
}

export default Navbar